async fn delete_inbox_item_removes_it_and_redirects() {
    let app = spawn_app().await;
    let client = register_and_login(&app.address, "delete@example.com", "securepassword123").await;

    // Capture an item
    client
        .post(format!("{}/inbox", &app.address))
